                  content: `body {
    transition: background 0.3s;
    font-family: Arial, sans-serif;
    min-height: 100vh;
    margin: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
}

.color-control {
    margin: 20px auto;
    width: 300px;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.color-label {
    width: 40px;
}

.value {
    width: 40px;
    font-weight: bold;
}

.rgb-preview {
    margin: 30px auto;
    padding: 20px;
    border-radius: 10px;
    background: #fff;
    width: 320px;
    box-shadow: 0 2px 8px #0002;
}

input[type="range"] {
    width: 200px;
    -webkit-appearance: none;
    background: #fff;
    border: none;
    height: 4px;    
    border-radius: 2px;
    outline: none;
}

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background: rgb(154, 107, 107);
    cursor: pointer;
    background: var(--thumb-color, rgb(154, 107, 107));
}

`,
